function roundUpToWholeG(amount: number): number {
  // Round to cents first to avoid float-precision artifacts like 100*1.10 = 110.00000000000001
  return Math.ceil(Math.round(amount * 100) / 100);
}

export function quote(
  _customer: { yearsWithMHPCO: number },
  items: Item[],
  _previousContracts?: number,
): number {
  if (items.length === 0) return PROCESSING_FEE;
  const basePremium = BASE_PREMIUMS[items[0].type];
  const premium = roundUpToWholeG(basePremium * FIRST_INSURANCE_SURCHARGE);
  return premium + PROCESSING_FEE;
}
